INSERT IGNORE INTO `pertanyaan_deteksi` (`id`, `sub_kategori_id`, `ruang_lingkup_id`, `pertanyaan_deteksi`, `index0`, `index1`, `index2`, `index3`, `index4`, `index5`, `created_at`, `updated_at`) VALUES
(1, 56, 1, 'Memperjelas peran dan tanggung jawab organisasi serta penyedia layanan dalam rangka mendeteksi peristiwa keamanan.', 'Belum adanya kejelasan tentang peran dan tanggung jawab organisasi serta penyedia layanan dalam rangka mendeteksi peristiwa keamanan', 'Peran dan tanggung jawab organisasi serta penyedia layanan dalam rangka mendeteksi peristiwa keamanan sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan', 'Peran dan tanggung jawab organisasi serta penyedia layanan dalam rangka mendeteksi peristiwa keamanan sudah diterapkan pada sebagian besar aspek tapi belum diformalkan.', 'Peran dan tanggung jawab organisasi serta penyedia layanan dalam rangka mendeteksi peristiwa keamanan sudah diterapkan pada seluruh aspek dan sudah diformalkan', 'Peran dan tanggung jawab organisasi serta penyedia layanan dalam rangka mendeteksi peristiwa keamanan sudah diterapkan pada seluruh aspek dan sudah diformalkan, dilakukan monitoring secara rutin, dan di review secara berkala meninjau kembali dan mengevaluasi efektivitasnya. Ada upaya untuk memastikan bahwa proses ini tetap relevan dan efisien seiring waktu.', 'Peran dan tanggung jawab organisasi serta penyedia layanan dalam rangka mendeteksi peristiwa keamanan sudah diterapkan pada seluruh aspek dan sudah diformalkan, dilakukan monitoring secara rutin, dan di review secara berkala meninjau kembali dan mengevaluasi efektivitasnya, proaktif melakukan perbaikan berkelanjutan dan adaptif terhadap perubahan lingkungan dan ancaman keamanan.', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(2, 56, 2, 'Penyelenggara Sistem Elektronik menyiapkan sistem dalam organisasi untuk mendeteksi, menganalisis, dan merespons peristiwa keamanan.', ' -  Belum ada sistem untuk mendeteksi peristiwa kamanan\r\n\r\n -  Belum ada sistem untuk menganalisis peristiwa kamanan\r\n\r\n -  Belum ada sistem untuk merespons peristiwa keamanan', ' -  Sistem untuk mendeteksi peristiwa keamanan sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan\r\n\r\n -  Sistem untuk menganalisis peristiwa keamanan sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan\r\n\r\n -  Sistem untuk merespons peristiwa keamanan sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan', ' -  Sistem untuk mendeteksi peristiwa keamanan sudah diterapkan pada sebagian besar aspek tapi belum diformalkan\r\n\r\n -  Sistem untuk menganalisis peristiwa keamanan sudah diterapkan pada sebagian besar aspek tapi belum diformalkan\r\n\r\n -  Sistem untuk merespons peristiwa keamanan sudah diterapkan pada sebagian besar aspek tapi belum diformalkan', ' -  Sistem untuk mendeteksi peristiwa keamanan sudah diterapkan pada seluruh aspek dan sudah diformalkan\r\n\r\n -  Sistem untuk menganalisis peristiwa keamanan sudah diterapkan pada seluruh aspek dan sudah diformalkan\r\n\r\n -  Sistem untuk merespons peristiwa keamanan sudah diterapkan pada seluruh aspek dan sudah diformalkan', ' -  Sistem untuk mendeteksi peristiwa keamanan sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala\r\n\r\n -  Sistem untuk menganalisis peristiwa keamanan sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala\r\n\r\n -  Sistem untuk merespons peristiwa keamanan sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala', ' -  Sistem untuk mendeteksi peristiwa keamanan sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala serta dilakukan otomatisasi\r\n\r\n -  Sistem untuk menganalisis peristiwa keamanan sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala serta dilakukan otomatisasi\r\n\r\n -  Sistem untuk merespons peristiwa keamanan sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala serta dilakukan otomatisasi', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(3, 57, 2, 'Melakukan proses pemantauan peristiwa keamanan siber, sesuai dengan peraturan, arahan, standar industri, dan aturan lainnya yang berlaku.', 'Belum dilakukan proses pemantauan peristiwa keamanan siber, sesuai dengan peraturan, arahan, standar industri, dan aturan lainnya yang berlaku', 'Proses pemantauan peristiwa keamanan siber sudah diterapkan\r\npada sebagian kecil aspek tapi belum diformalkan sesuai dengan peraturan, arahan, standar industri, dan aturan lainnya yang berlaku', 'Proses pemantauan peristiwa keamanan siber sudah diterapkan\r\npada sebagian besar aspek tapi belum diformalkan sesuai dengan peraturan, arahan, standar industri, dan aturan lainnya yang berlaku', 'Proses pemantauan peristiwa keamanan siber sudah diterapkan\r\npada seluruh aspek dan sudah diformalkan sesuai dengan peraturan, arahan, standar industri, dan aturan lainnya yang berlaku', 'Proses pemantauan peristiwa keamanan siber sudah diterapkan\r\npada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala sesuai dengan peraturan, arahan, standar industri, dan aturan lainnya yang berlaku', 'Proses pemantauan peristiwa keamanan siber sudah diterapkan\r\npada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala serta dilakukan otomatisasi sesuai dengan peraturan, arahan, standar industri, dan aturan lainnya yang berlaku', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(4, 57, 2, 'Melakukan pemantauan dan kontrol jaringan pada setiap titik masuk ke  jaringan organisasi. ', 'Belum dilakukan proses pemantauan dan kontrol jaringan pada setiap titik masuk ke  jaringan organisasi', 'Proses pemantauan dan kontrol jaringan pada setiap titik masuk ke  jaringan organisasi sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan', 'Proses pemantauan dan kontrol jaringan pada setiap titik masuk ke  jaringan organisasi sudah diterapkan pada sebagian besar aspek tapi belum diformalkan', 'Proses pemantauan dan kontrol jaringan pada setiap titik masuk ke  jaringan organisasi sudah diterapkan pada seluruh aspek dan sudah diformalkan', 'Proses pemantauan dan kontrol jaringan pada setiap titik masuk ke  jaringan organisasi sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala', 'Proses pemantauan dan kontrol jaringan pada setiap titik masuk ke  jaringan organisasi sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala serta dilakukan otomatisasi', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(5, 58, 2, 'Penyelenggara Sistem Elektronik melakukan pengujian secara periodik tentang efektifitas perangkat dan prosedur untuk mendeteksi peristiwa keamanan sebagaimana mestinya.', ' -  Belum ada SOP Pengujian Perangkat Sistem Elektronik\r\n\r\n- Belum ada SOP Pendeteksian Peristiwa Keamanan Siber', ' - SOP Pengujian Perangkat Sistem Elektronik sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan\r\n\r\n- SOP Pendeteksian Peristiwa Keamanan Siber sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan', ' - SOP Pengujian Perangkat Sistem Elektronik sudah diterapkan pada sebagian besar aspek tapi belum diformalkan\r\n\r\n- SOP Pendeteksian Peristiwa Keamanan Siber sudah diterapkan pada sebagian besar aspek tapi belum diformalkan', ' - SOP Pengujian Perangkat Sistem Elektronik sudah diterapkan pada seluruh aspek dan sudah diformalkan\r\n\r\n- SOP Pendeteksian Peristiwa Keamanan Siber sudah diterapkan pada seluruh aspek dan sudah diformalkan', ' - SOP Pengujian Perangkat Sistem Elektronik sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala\r\n\r\n- SOP Pendeteksian Peristiwa Keamanan Siber sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala', ' - SOP Pengujian Perangkat Sistem Elektronik sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala serta dilakukan perbaikan\r\n\r\n- SOP Pendeteksian Peristiwa Keamanan Siber sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala serta dilakukan perbaikan', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(6, 59, 1, 'Informasi hasil pendeteksian kejadian keamanan diberitahukan kepada pihak yang terkait sesuai dengan persetujuan manajemen organisasi.', ' -  Belum ada SOP Penyampaian Informasi hasil pendeteksian kejadian keamanan\r\n\r\n- Belum ada dokumen NDA', ' -  SOP Penyampaian Informasi hasil pendeteksian kejadian keamanan sudah diterapkan pada sebagian aspek tapi belum diformalkan\r\n\r\n- Dokumen NDA sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan', ' -  SOP Penyampaian Informasi hasil pendeteksian kejadian keamanan sudah diterapkan pada sebagian besar aspek tapi belum diformalkan\r\n\r\n- Dokumen NDA sudah diterapkan pada sebagian besar aspek tapi belum diformalkan', ' -  SOP Penyampaian Informasi hasil pendeteksian kejadian keamanan sudah diterapkan pada seluruh aspek dan sudah diformalkan\r\n\r\n- Dokumen NDA sudah diterapkan pada seluruh aspek dan sudah diformalkan', ' -  SOP Penyampaian Informasi hasil pendeteksian kejadian keamanan sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala\r\n\r\n- Dokumen NDA sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala', ' -  SOP Penyampaian Informasi hasil pendeteksian kejadian keamanan sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala serta dilakukan perbaikan\r\n\r\n- Dokumen NDA sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan direview secara berkala serta dilakukan perbaikan', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(7, 59, 1, 'Penyelenggara Sistem Elektronik melakukan reviu dan peningkatan prosedur pendeteksian peristiwa keamanan secara berkala.', ' -  Belum ada Review prosedur secara berkala', ' -  Review prosedur secara berkala sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan', ' -  Review prosedur secara berkala sudah diterapkan pada sebagian besar aspek tapi belum diformalkan', ' -  Review prosedur secara berkala sudah diterapkan pada seluruh aspek dan sudah diformalkan', ' -  Review prosedur secara berkala sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan dikaji secara berkala', ' -  Review prosedur secara berkala sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring dan dikaji secara berkala serta dilakukan perbaikan', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(8, 60, 1, 'Penyelenggara Sistem Elektronik menetapkan dan menerapkan prosedur untuk mengidentifikasi dan mengelola ambang batas terhadap operasional jaringan dan arus informasi yang diharapkan antara pengguna, penyelenggara, dan sistem.', '-  Belum ada SOP Identifikasi Operasional Sistem Elektronik\r\n\r\n- Belum ada SOP Pengelolaan Operasional Sistem Elektronik\r\n\r\n- Belum ada Dokumen Monitoring Kapasitas Sistem Elektronik', '- SOP Identifikasi Operasional Sistem Elektronik sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan\r\n\r\n- SOP Pengelolaan Operasional Sistem Elektronik sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan\r\n\r\n- Dokumen Monitoring Kapasitas Sistem Elektronik sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan', '- SOP Identifikasi Operasional Sistem Elektronik sudah diterapkan pada sebagian besar aspek tapi belum diformalkan\r\n\r\n- SOP Pengelolaan Operasional Sistem Elektronik sudah diterapkan pada sebagian besar aspek tapi belum diformalkan\r\n\r\n- Dokumen Monitoring Kapasitas Sistem Elektronik sudah diterapkan pada sebagian besar aspek tapi belum diformalkan', '- SOP Identifikasi Operasional Sistem Elektronik sudah diterapkan pada seluruh aspek dan sudah diformalkan\r\n\r\n- SOP Pengelolaan Operasional Sistem Elektronik sudah diterapkan pada seluruh aspek dan sudah diformalkan\r\n\r\n- Dokumen Monitoring Kapasitas Sistem Elektronik sudah diterapkan pada seluruh aspek dan sudah diformalkan', ' - SOP Identifikasi Operasional Sistem Elektronik sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, dan direview secara berkala\r\n\r\n- SOP Pengelolaan Operasional Sistem Elektronik sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, dan direview secara berkala\r\n\r\n- Dokumen Monitoring Kapasitas Sistem Elektronik sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, dan direview secara berkala', '- SOP Identifikasi Operasional Sistem Elektronik sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, direview secara berkala, dan dilakukan perbaikan, atau otomatisasi jika teknis\r\n\r\n- SOP Pengelolaan Operasional Sistem Elektronik sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, direview secara berkala, dan dilakukan perbaikan, atau otomatisasi jika teknis\r\n\r\n- Dokumen Monitoring Kapasitas Sistem Elektronik sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, direview secara berkala, dan dilakukan perbaikan, atau otomatisasi jika teknis', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(9, 61, 2, 'Kejadian keamanan yang terdeteksi dianalisis untuk memahami target dan metode serangan', '- Belum ada tools untuk melaksanakan analisis terhadap peristiwa siber\r\n\r\n- Belum ada Petunjuk Teknis Analisis terhadap Peristiwa Siber\r\n\r\n- Belum ada laporan analisis terhadap peristiwa siber yang terdeteksi', '- Tools untuk melaksanakan analisis terhadap peristiwa siber sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan\r\n\r\n- Petunjuk Teknis Analisis terhadap Peristiwa Siber sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan\r\n\r\n- Laporan analisis terhadap peristiwa siber yang terdeteksi sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan', '- Tools untuk melaksanakan analisis terhadap peristiwa siber sudah diterapkan pada sebagian besar aspek tapi belum diformalkan\r\n\r\n- Petunjuk Teknis Analisis terhadap Peristiwa Siber sudah diterapkan pada sebagian besar aspek tapi belum diformalkan\r\n\r\n- Laporan analisis terhadap peristiwa siber yang terdeteksi sudah diterapkan pada sebagian besar aspek tapi belum diformalkan', '- tools untuk melaksanakan analisis terhadap peristiwa siber sudah diterapkan pada seluruh aspek dan sudah diformalkan\r\n\r\n- Petunjuk Teknis analisis terhadap peristiwa siber sudah diterapkan pada seluruh aspek dan sudah diformalkan\r\n\r\n- laporan analisis terhadap peristiwa siber yang terdeteksi sudah diterapkan pada seluruh aspek dan sudah diformalkan', '- Tools untuk melaksanakan analisis terhadap peristiwa siber sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, dan direview secara berkala\r\n\r\n- Petunjuk Teknis Analisis terhadap Peristiwa Siber sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, dan direview secara berkala\r\n\r\n- Laporan analisis terhadap peristiwa siber yang terdeteksi sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, dan direview secara berkala', '- Tools untuk melaksanakan analisis terhadap peristiwa siber sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, direview secara berkala, dan dilakukan perbaikan, atau otomatisasi jika teknis\r\n- Petunjuk Teknis Analisis terhadap Peristiwa Siber sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, direview secara berkala, dan dilakukan perbaikan, atau otomatisasi jika teknis\r\n- Laporan analisis terhadap peristiwa siber yang terdeteksi sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, direview secara berkala, dan dilakukan perbaikan, atau otomatisasi jika teknis', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(10, 61, 2, 'Identifikasi peristiwa keamanan secara akurat dengan menerapkan prosedur untuk melakukan analisis korelasi insiden keamanan dan analisis komparatif dengan informasi ancaman yang diperoleh dari luar organisasi.', '- Belum ada SOP Investigasi Insiden Keamanan Siber\r\n\r\n-  Belum ada Laporan Investigasi Insiden Keamanan Siber', '- SOP Investigasi Insiden Keamanan Siber sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan\r\n\r\n- Laporan Investigasi Insiden Keamanan Siber sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan', '- SOP Investigasi Insiden Keamanan Siber sudah diterapkan pada sebagian besar aspek tapi belum diformalkan\r\n\r\n- Laporan Investigasi Insiden Keamanan Siber sudah diterapkan pada sebagian besar aspek tapi belum diformalkan', '- SOP Investigasi Insiden Keamanan Siber sudah diterapkan pada seluruh aspek dan sudah diformalkan\r\n\r\n- Laporan Investigasi Insiden Keamanan Siber sudah diterapkan pada seluruh aspek dan sudah diformalkan', '- SOP Investigasi Insiden Keamanan Siber sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, dan direview secara berkala\r\n\r\n- Laporan Investigasi Insiden Keamanan Siber sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, dan direview secara berkala', '- SOP Investigasi Insiden Keamanan Siber sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, direview secara berkala, dan dilakukan perbaikan, atau otomatisasi jika teknis\r\n\r\n- Laporan Investigasi Insiden Keamanan Siber sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, direview secara berkala, dan dilakukan perbaikan, atau otomatisasi jika teknis', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(11, 62, 2, 'Identifikasi dampak peristiwa keamanan, termasuk dampaknya terhadap organisasi lain yang relevan.', 'Belum ada dokumen Manajemen Risiko berupa dokumen Penilaian Risiko (Risk Assessment), IRP (Incident Response Program and Planning), DRP (Disaster Recovery Planning), dan BIA (Business Impact Analysis)', 'Dokumen Manajemen Risiko (dokumen Penilaian Risiko (Risk Assessment), IRP (Incident Response Program and Planning), DRP (Disaster Recovery Planning), dan BIA (Business Impact Analysis) sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan', 'Dokumen Manajemen Risiko (dokumen Penilaian Risiko (Risk Assessment), IRP (Incident Response Program and Planning), DRP (Disaster Recovery Planning), dan BIA (Business Impact Analysis) sudah diterapkan pada sebagian besar aspek tapi belum diformalkan', 'Dokumen Manajemen Risiko (dokumen Penilaian Risiko (Risk Assessment), IRP (Incident Response Program and Planning), DRP (Disaster Recovery Planning), dan BIA (Business Impact Analysis) sudah diterapkan pada seluruh aspek dan sudah diformalkan ', 'Dokumen Manajemen Risiko (dokumen Penilaian Risiko (Risk Assessment), IRP (Incident Response Program and Planning), DRP (Disaster Recovery Planning), dan BIA (Business Impact Analysis) sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, dan direview secara berkala\r\n\r\n\r\n', 'Dokumen Manajemen Risiko (dokumen Penilaian Risiko (Risk Assessment), IRP (Incident Response Program and Planning), DRP (Disaster Recovery Planning), dan BIA (Business Impact Analysis) sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, direview secara berkala, dan dilakukan perbaikan, atau otomatisasi jika teknis', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
(12, 63, 1, 'Hasil analisis peristiwa siber didokumentasikan, serta dilaporkan kepada pihak manajemen sesuai ketentuan.', 'Belum ada proses dokumentasi hasil analisis peristiwa siber yang dilaporkan kepada pihak manajemen sesuai ketentuan.', 'Proses dokumentasi hasil analisis peristiwa siber yang dilaporkan kepada pihak manajemen sesuai ketentuan sudah diterapkan pada sebagian kecil aspek tapi belum diformalkan', 'Proses dokumentasi hasil analisis peristiwa siber yang dilaporkan kepada pihak manajemen sesuai ketentuan sudah diterapkan pada sebagian besar aspek tapi belum diformalkan', 'Proses dokumentasi hasil analisis peristiwa siber yang dilaporkan kepada pihak manajemen sesuai ketentuan sudah diterapkan pada seluruh aspek dan sudah diformalkan', 'Proses dokumentasi hasil analisis peristiwa siber yang dilaporkan kepada pihak manajemen sesuai ketentuan sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, dan direview secara berkala', 'Proses dokumentasi hasil analisis peristiwa siber yang dilaporkan kepada pihak manajemen sesuai ketentuan sudah diterapkan pada seluruh aspek dan sudah diformalkan, dimonitoring, direview secara berkala, dan dilakukan perbaikan, atau otomatisasi jika teknis', '2026-03-11 06:49:00', '2026-03-11 06:49:00'),
